class Solution {
public:
    int minFlipsMonoIncr(string s) {
        int flips = 0;
        int zeroCount = 0;
        for (char c : s) {
            if (c == '0') {
                zeroCount++;
            }
            flips = min(flips, zeroCount);
        }
        return flips;
    }
};
